onClick:
(async () => {
  // LẤY TẤT CẢ DỮ LIỆU TỪ BẢNG (Không cần nhấn tick xanh)
  const allRows = Kiem_Ke_Cong_Cu.tableData;

  if (!allRows || allRows.length === 0) {
    showAlert("⚠️ Bảng dữ liệu trống!", "warning");
    return;
  }

  try {
    showAlert("⏳ Đang lưu toàn bộ dữ liệu...", "info");

    for (let i = 0; i < allRows.length; i++) {
      const row = allRows[i];

      // GỬI DỮ LIỆU ĐANG CÓ TRÊN BẢNG LÊN
      // Lưu ý: Nếu bạn có filter/sort, cách này sẽ lưu tất cả. 
      // Hãy cẩn thận nếu bạn chỉ muốn lưu 1 vài dòng.
      await Action_Luu_Kiem_Ke_Tool.run({
          code: row["Mã vật liệu / 物料编码"],
          qty: Number(row["Kiểm Kê Thực Tế / 本月实际盘点"]),
          reason: row["Nguyên Nhân Chênh Lệch / 差异原因"] ?? '',
          notes: row["Ghi Chú / 备注"] ?? ''
      });
    }

    showAlert("✅ Lưu toàn bộ bảng thành công!", "success");
    await Get_Inventory_Data.run();
    resetWidget('Kiem_Ke_Cong_Cu', true);

  } catch (err) {
    showAlert("❌ Lỗi: " + err.message, "error");
  }
})()
